def search_matrix(matrix: list[list[int]], target: int) -> bool:
    if not matrix or not matrix[0]:
        return False
    rows, cols = len(matrix), len(matrix[0])
    low, high = 0, rows * cols - 1
    while low <= high:
        mid = (low + high) // 2
        row = mid // cols
        col = mid % cols
        if matrix[row][col] == target:
            return True
        elif matrix[row][col] < target:
            low = mid + 1
        else:
            high = mid - 1
    return False
```

def search_in_matrix(grid: list[list[int]], val: int) -> bool:
    if not grid or not grid[0]:
        return False
    m, n = len(grid), len(grid[0])
    left, right = 0, m * n - 1
    while left <= right:
        middle = (left + right) // 2
        r = middle // n
        c = middle % n
        if grid[r][c] == val:
            return True
        elif grid[r][c] < val:
            left = middle + 1
        else:
            right = middle - 1
    return False

