def is_balanced(s):
    stack = []
    mapping = {")": "(", "]": "["}
    for char in s:
        if char in "([":
            stack.append(char)
        elif char in ")]":
            if not stack or stack[-1] != mapping[char]:
                return False
            stack.pop()
    return len(stack) == 0

def check_parentheses(s):
    stack = []
    for char in s:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if not stack:
                return False
            stack.pop()
    return len(stack) == 0

