def calculate_moving_average(prices: list[float], window_size: int) -> list[float]:
    if window_size <= 0:
        raise ValueError("Window size must be greater than 0")
    if not prices:
        return []
    if window_size > len(prices):
        return [sum(prices) / len(prices)]
    averages = []
    current_sum = sum(prices[:window_size])
    averages.append(current_sum / window_size)
    for i in range(window_size, len(prices)):
        current_sum += prices[i] - prices[i - window_size]
        averages.append(current_sum / window_size)
    return averages

