def longest_subarray_sum_at_most_k(nums: list[int], k: int) -> tuple[int, int]:
    if not nums or k < 0:
        return (-1, -1)
    n = len(nums)
    left = 0
    current_sum = 0
    max_len = 0
    best_range = (-1, -1)
    for right in range(n):
        current_sum += nums[right]
        while current_sum > k and left <= right:
            current_sum -= nums[left]
            left += 1
        if current_sum <= k and left <= right:
            length = right - left + 1
            if length > max_len:
                max_len = length
                best_range = (left, right)
    return best_range

