def merge_intervals_functional(intervals: list[list[int]]) -> list[list[int]]:
    """Merges overlapping intervals using recursion."""
    if not intervals:
        return []

    sorted_intervals = sorted(intervals, key=lambda x: x[0])

    def merge_recursive(left: list[list[int]], right: list[list[int]]) -> list[list[int]]:
        if not right:
            return left
        curr = right[0]
        if not left:
            return merge_recursive([curr], right[1:])
        prev = left[-1]
        if curr[0] <= prev[1]:
            left[-1] = [prev[0], max(prev[1], curr[1])]
            return merge_recursive(left, right[1:])
        else:
            left.append(curr)
            return merge_recursive(left, right[1:])

    return merge_recursive([], sorted_intervals)

