def normalize_scores(scores):
    if not scores:
        return []
    lo = min(scores)
    hi = max(scores)
    if lo == hi:
        return [0.0 for _ in scores]
    span = hi - lo
    return [(x - lo) / span for x in scores]

def rescale_to_unit_interval(values):
    if not values:
        return []
    lo = min(values)
    hi = max(values)
    if lo == hi:
        return [0.0 for _ in values]
    span = hi - lo
    return [(x - lo) / span for x in values]

